var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"네, 그럼 또 다음에 연락 드릴게요. 고맙습니다.","JPN":"はい、ではまた\\nご連絡差し上げます。ありがとうございます。","ENG":"Yes, we'll be in touch. Thank you.","TWN":"好的，下次我會再和你聯絡的，謝謝你。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"......휴우, 온종일 발로 뛰었더니 종아리가 쑤시네.","JPN":"……ふう、一日中\\n歩き回ってたら足が棒になってしまったわ。","ENG":"Phew, running around all day got my calves all sore.","TWN":"……呼，跑了一整天，小腿都發酸了呢。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"섭외도 많고, 시청자도 계속 늘고 있는데......","JPN":"出演依頼も、視聴者数も増え続けてるのに……","ENG":"Our bookings are going up along with the ratings...","TWN":"明明有很多邀約，觀眾也在不斷增加……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"요즘 들어 느껴지는 이 허전한 기분은 뭐지?","JPN":"最近感じる、この物足りなさは何なのかしら……","ENG":"So why do I feel so empty these days?","TWN":"但最近這股空虛感是怎麼回事？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"웃는 게 부자연스럽다고 오프닝을 스무 번이나 찍은 건 심했다고 생각하지만......","JPN":"笑顔がぎこちないからって、オープニング映像を20回も撮り直させたのはひどいと思いますけど……","ENG":"I mean, I think it was a tad much when she had us shoot 20 takes of the opening scene because our smiles were awkward...","TWN":"雖然因為我笑得不夠自然，拍了20次開場有點過分……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"돈은 최저시급 언저리인 주제에, 일은 쉴 틈 없이 부려먹기만 하고.","JPN":"もらえるお金は最低賃金ギリギリだし、そのくせ休む間もなくこき使ってくれるし。","ENG":"She pays us barely more than the minimum wage and keeps working our butts off.","TWN":"明明給的是最低工資，工作也沒有休息空檔，還到處使喚我。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......네? 초과근무? 노동자권리?","JPN":"……え？　超過勤務？　労働者の権利？","ENG":"Sorry? Overtime bonus? Workers' rights?","TWN":"……咦？加班？勞動者權利？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"저는 그런 어려운 말 몰라요.","JPN":"そんな難しい言葉は知りません。","ENG":"That all sounds too complicated for me.","TWN":"我不懂這些複雜的事情。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"간만에 제과점이나 들를까.","JPN":"久しぶりに美味しいスイーツのお店にでも寄ろうかしら。","ENG":"Maybe I'll go pick up some pastries.","TWN":"久違地去趟麵包店吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"아~ 피곤해. 일정 때문에 사흘 내내 잠도 제대로 못 잤잖아.","JPN":"あぁ～疲れたわ。いくらなんでもスケジュールが\\nきつすぎだわ。三日もろくに眠れてないじゃないの。","ENG":"Ugh, I'm pooped. I barely slept a wink for the past three days because of our schedule.","TWN":"啊～累死了。這個行程讓我們三天都沒睡好覺。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"그럴 땐 내 기절베개를 써보는 건 어떠냥?","JPN":"そんなときは、ボミの気絶枕を使ってみたらどうかにゃ？","ENG":"Why don't you try using my super comfy pillow?","TWN":"要不要我的昏睡枕頭借妳一下啊喵？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"......네건 왠지 캣닙 냄새가 나서 싫어.","JPN":"……あなたのは、キャットニップのにおいがするから嫌なのよ。","ENG":"No thanks. Yours smells like catnip for some reason.","TWN":"……我討厭妳枕頭上的貓薄荷味道。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"그나저나 어깨 좀 잘 주물러봐. 그렇게 톡톡 건들지만 말고.","JPN":"それはそうと、もっとちゃんと揉めないの？　それじゃ肩揉みというより、肩いじりじゃないの。","ENG":"Anyway, give me a proper backrub. Don't just tap at it like that.","TWN":"不過給我揉一揉肩膀吧。不要只是這樣啪嗒啪嗒地摸而已。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"냐항...... 내가 할 줄 아는 안마라곤 꾹꾹이 밖에 없는 걸~","JPN":"にゃはぁ……ボミに使えるマッサージ\\nスキルは、もみもみだけなのにゃ～。","ENG":"Nya... But the only massage I know how to do is kneading...","TWN":"喵……我會做的按摩只有這個喵～"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"흥, 대체 남들 일할 때 잠자는 거 빼고 잘 하는 게 뭐야?","JPN":"フン。人が働いてるときに寝ること以外、\\n得意なことなんてないんでしょ？","ENG":"Hmpf. Is there anything you can do well, other than napping at work?","TWN":"哼，除了在別人工作時睡覺，妳到底有什麼做得好？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"응? 보미가 잘하는 거?","JPN":"えっ？　ボミの得意なこと？","ENG":"Hm? Something I'm good at?","TWN":"嗯？普美擅長的嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"방심하고 있는 사람 간지럽히기!","JPN":"……油断してる相手をくすぐることにゃ！","ENG":"Surprise tickle attacks!","TWN":"就是對毫無防備的人搔癢！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"......크흡!","JPN":"……ぐふッ！","ENG":"Pfft!","TWN":"……嗚噗！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"아하하하하하!","JPN":"アハハハハハッ！","ENG":"Ah hah hah hah!","TWN":"啊哈哈哈哈哈！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"냐하항, 루미가 좋아하는 것 같아서 기쁘다냥.","JPN":"にゃははぁん、ルミに喜んでもらえて嬉しいにゃ。","ENG":"Nyah! I'm glad you like it, Lumi.","TWN":"喵哈哈，看到魯米這麼開心我也好高興喵。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"아하하하! 그만, 그...... 그만!","JPN":"あっははは！　やめ、や……やめて！","ENG":"Ah hah hah hah! Stop it... Stop... Enough!","TWN":"啊哈哈哈！夠、夠了……停！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"이이...... 그만 하라니까!","JPN":"ぐぬぬ……やめなさいったら！","ENG":"Argh... I said stop it!","TWN":"妳……快住手！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"얘들아, 나 왔......","JPN":"みんな～、ただい……","ENG":"Girls, I'm home—","TWN":"我來了，各位……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_BIG"},{"id":"L34_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"앗...... 루미 발길질에 벽이 부서져버렸당......","JPN":"あっ……ルミの蹴りで壁が壊れてしまったにゃ……","ENG":"Oh... Lumi kicked the wall down...","TWN":"啊……魯米把牆踢壞了……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"으아, 언니 화내시겠다. 어떡해.","JPN":"あう……メグミさん、きっと怒るよね。どうしよう……","ENG":"Uh-oh... Ina's going to be furious. What are we going to do?","TWN":"嗚啊，姐姐肯定會生氣的，怎麼辦？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"어머, 괜찮니? 어디 다친 데는 없고?","JPN":"まあ、大丈夫？　どこかケガしてない？","ENG":"Oh dear, are you alright? You didn't hurt yourself?","TWN":"唉呀，妳沒事吧？有沒有哪裡受傷？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"매, 매니저...... 이건 그러니까......","JPN":"マ、マネージャー……えっと、これは……","ENG":"I-Ina... It's not what you think...","TWN":"經、經紀人……這是因為……"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"응? 방금 뭐라고......","JPN":"えっ？　今なんて……","ENG":"Hm? Wait, what did you just say?","TWN":"嗯？妳剛剛說什麼...."},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"음, 벽은 이 정도 균열이면 내가 땜질로 메울 수 있어.","JPN":"うーん、この程度の亀裂なら、私でも補修できると思うわ。","ENG":"Oh, I can patch that wall together in no time.","TWN":"喔，只是這種程度的裂縫，我可以把它修好。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"이런 사소한 건 신경 쓰지 말고 다들 쉬도록 해. 내일도 새벽부터 바쁘잖아?","JPN":"こんな些細なことに気を遣わなくていいのよ。\\nみんなゆっくり休みなさい。明日も朝早いでしょう？","ENG":"Don’t worry about this and get some rest, everyone. You've got an early start tomorrow morning, don't you?","TWN":"妳們不用在意這些小事，都快點休息吧。明天也會很忙對吧？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"어...... 으응.","JPN":"えっ……そ、そうね。","ENG":"Um... Yeah.","TWN":"喔……好。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"......가은아, 이나 언니가 원래 저랬었나?","JPN":"……ユキ、メグミさんってあんなだったっけ？","ENG":"Hey, Gaeun, was she always like that?","TWN":"……嘉恩，理娜姐原來是那種性格嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"응, 내가 늘 봐오던 친절한 모습 그대로야.","JPN":"ええ、いつも私たちが見てる親切なマネージャーの姿だわ。","ENG":"Sure, it's her same sweet self I always knew.","TWN":"嗯，就像我平時看到的一樣親切。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그런가......?","JPN":"そうかな……？","ENG":"Is it?","TWN":"是嗎……？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"아 참, 오는 길에 조각케이크를 종류별로 사왔으니까, 먹고 싶은 만큼 먹어도 돼.","JPN":"そうそう、途中でバラ売りケーキを\\nいろいろ買ってきたわ。好きなだけ食べてね。","ENG":"Oh, by the way, I picked up some cake on the way here. Help yourselves to all you'd like.","TWN":"啊，對了。我在回來的路上買了幾個奶油蛋糕，妳們想吃就吃吧。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"이예~!","JPN":"やったにゃ～！","ENG":"Hooray!","TWN":"耶～!"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"앗, 저녁시간 지났는데. 정말...... 먹어도 돼요?","JPN":"あっ、夕食の時間は過ぎてるのに、本当に……食べていいんですか？","ENG":"Oh... But it's past our dinner time. Can we... really have some?","TWN":"啊，可是已經過了晚餐時間，我們真的……可以吃嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"어머, 얘는. 내가 한 입으로 두 말하는 거 봤니?","JPN":"あらやだ。私が嘘を言ったことがあったかしら？","ENG":"Oh, come on sweetie. Have I ever lied to you?","TWN":"哎呀，妳這孩子，難道妳要我說第二遍？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"너희도 요즘 많이 힘들었으니까.","JPN":"あなたたち、最近大変だったものね。","ENG":"I know you've all been through a lot lately.","TWN":"畢竟妳們最近很忙。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"그에 대한 보상이라곤 할 수는 없겠지만...... 이렇게라도 격려해주고 싶었어.","JPN":"そのお詫びと言っては何だけど……\\nせめて労いたいと思ったの。","ENG":"I know this doesn't make up for all of that... But I wanted to give you a pat on the back at least.","TWN":"雖然不能當作是給妳們的補償……但我想要用蛋糕給妳們一點鼓勵。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"흑, 언니...... 저 감동했어요.","JPN":"ふぐっ、メグミさん……私感動しちゃいました。","ENG":"Aww, Ina... I'm so touched...","TWN":"嗚，姐姐……我好感動。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"뚝! 뭘 이런 걸로 눈물까지 흘려.","JPN":"もう、こんなことで泣かないの！","ENG":"Oh, don't cry. This is nothing to cry over.","TWN":"喂！這是什麼事情，連眼淚都流下來了。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"아, 루미도 이리와. 네가 좋아하는 체리 케이크도 사왔거든.","JPN":"ルミもこっちにいらっしゃい。\\nあなたの好きなチェリーケーキも買ってきたのよ。","ENG":"Come on, Lumi. I got you your favorite cherry cake too.","TWN":"啊，魯米也快過來，我也買了妳最喜歡的櫻桃蛋糕。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"......체리? 그거 좋아한다고 내 프로필에 멋대로 쓴 건 매니저였잖아?","JPN":"……アタシがチェリー好き？　それはマネージャーが\\n勝手にプロフィールに書いたんでしょう？","ENG":"Cherry? I never said I liked cherries. You just put that on my profile without asking!","TWN":"……櫻桃？那不是經紀人擅自在我的個人檔案加上去的嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"어머, 싫어했나?","JPN":"あら、チェリーはお嫌いだったかしら？","ENG":"Oh my, you don't like cherries?","TWN":"哎呀，妳不喜歡啊？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"그럼 이제부터 차근차근 좋아하게 되면 되겠지?","JPN":"なら、これからじっくり\\n好きになっていけばいいんじゃない？","ENG":"Then I guess you can learn to start liking it, no?","TWN":"那妳現在慢慢喜歡上不就行了？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"......아으.","JPN":"……あぅ。","ENG":"Ugh...","TWN":"……啊嗚。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"아니, 딱히 체리를 싫어한다곤 안 했고......","JPN":"べ、別にチェリーが嫌いだなんて言ってないし……","ENG":"I mean, I never said I dislike it either...","TWN":"不是，我也沒說我不喜歡櫻桃……"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"뭐어, 성의를 봐서 잘 먹을게.","JPN":"まあ、誠意に免じていただくことにするわ。","ENG":"Fine, I'll have some since you were kind enough to buy it.","TWN":"好吧，看在妳這麼有誠意的份上，我就吃吧。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"후훗, 고마워. 정말로.","JPN":"ふふっ、ありがとう。本当に……","ENG":"Heh, thanks. Seriously.","TWN":"呵呵，謝謝妳，真的。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"칫......","JPN":"ちぇっ……","ENG":"Hmpf...","TWN":"切……"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"......흐음?","JPN":"……ふーん？","ENG":"Hmm?","TWN":"……嗯？"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"뭐, 체리도...... 가끔은 먹을만하려나.","JPN":"まあ、チェリーも……たまには悪くないかもね。","ENG":"Well, I guess cherries aren't so bad after all.","TWN":"好吧，櫻桃……偶爾吃一次也不錯。"},"stage":{"bg":"DORMITORY_2","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};